from flask import Flask, request, jsonify
import jwt
import requests

app = Flask(__name__)
SECRET_KEY = "your-secret-key"

@app.route('/<service>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def proxy_request(service):
    token = request.headers.get('Authorization', None)
    if not token:
        return jsonify({"error": "Missing or invalid token"}), 401

    try:
        payload = jwt.decode(token, SECRET_KEY, verify=False)
        user_claims = payload['user_claims']
    except jwt.ExpiredSignatureError:
        return jsonify({"error": "Token has expired"}), 401
    except jwt.DecodeError:
        return jsonify({"error": "Invalid token"}), 401

    # Forward the request to the upstream service with user claims included
    upstream_url = f"http://localhost:{service}_port/api/{request.endpoint[1]}"
    headers = {'Content-Type': request.headers['Content-Type'], 'Authorization': token}

    if request.method == 'GET':
        response = requests.get(upstream_url, headers=headers)
    elif request.method == 'POST':
        response = requests.post(upstream_url, json=request.get_json(), headers=headers)
    elif request.method == 'PUT':
        response = requests.put(upstream_url, json=request.get_json(), headers=headers)
    elif request.method == 'DELETE':
        response = requests.delete(upstream_url, headers=headers)

    return response

if __name__ == "__main__":
    app.run(debug=True)